INSERT INTO cards (deck_id, front, back) VALUES 
('11db8175-ec5f-4c76-b026-b2ad73e71829', 'Fitts''s Law', 'The time to reach a target is a function of the distance to and size of the target. Larger and closer targets are easier to select.'),
('11db8175-ec5f-4c76-b026-b2ad73e71829', 'Hick''s Law', 'The time to make a decision increases logarithmically with the number of options available.'),
('11db8175-ec5f-4c76-b026-b2ad73e71829', 'Miller''s Rule', 'The average person can only keep 7 (±2) items in their working memory at once.'),
('11db8175-ec5f-4c76-b026-b2ad73e71829', 'Jakob''s Law', 'Users spend most of their time on other sites, so they prefer your site to work the same way as all the other sites they already know.'),
('11db8175-ec5f-4c76-b026-b2ad73e71829', 'Law of Proximity', 'Objects near each other are perceived as belonging to the same group or having similar functions.'),
('11db8175-ec5f-4c76-b026-b2ad73e71829', 'Law of Similarity', 'Objects that share visual characteristics (color, shape, size) are perceived as related or grouped together.'),
('11db8175-ec5f-4c76-b026-b2ad73e71829', 'Law of Prägnanz', 'People perceive complex shapes in the simplest form possible. Good design should be simple and uncluttered.'),
('11db8175-ec5f-4c76-b026-b2ad73e71829', 'Pareto Principle', '80% of effects come from 20% of causes. In UX: 80% of users typically use only 20% of features.'),
('11db8175-ec5f-4c76-b026-b2ad73e71829', 'Parkinson''s Law', 'Work expands to fill the time available. In UX: Users will take as much time as you give them to complete a task.'),
('11db8175-ec5f-4c76-b026-b2ad73e71829', 'Zeigarnik Effect', 'People remember interrupted or incomplete tasks better than completed ones. Progress indicators leverage this effect.');
INSERT INTO cards (deck_id, front, back) VALUES 
('11db8175-ec5f-4c76-b026-b2ad73e71829', 'Affordance', 'The perceived or actual properties of an object that suggest how it should be used (e.g., buttons appear clickable).'),
('11db8175-ec5f-4c76-b026-b2ad73e71829', 'Signifier', 'A perceivable indicator that communicates appropriate behavior to a person (e.g., underlined text suggests a link).'),
('11db8175-ec5f-4c76-b026-b2ad73e71829', 'Feedback', 'Communicating the result of an action to inform users that their action was received and processed.'),
('11db8175-ec5f-4c76-b026-b2ad73e71829', 'Visibility', 'Making relevant parts of the system observable to users so they know what actions are available.'),
('11db8175-ec5f-4c76-b026-b2ad73e71829', 'Mapping', 'The relationship between controls and their effects. Good mapping uses spatial and cultural conventions.'),
('11db8175-ec5f-4c76-b026-b2ad73e71829', 'Constraint', 'Limiting the possible actions available to prevent errors and guide user behavior toward successful outcomes.'),
('11db8175-ec5f-4c76-b026-b2ad73e71829', 'Consistency', 'Similar operations and elements should behave the same way throughout the interface to reduce learning time.'),
('11db8175-ec5f-4c76-b026-b2ad73e71829', 'Error Prevention', 'Good design prevents problems from occurring in the first place by eliminating error-prone conditions.'),
('11db8175-ec5f-4c76-b026-b2ad73e71829', 'Recognition vs Recall', 'It''s easier to recognize something than recall it from memory. Show don''t tell - make options visible.'),
('11db8175-ec5f-4c76-b026-b2ad73e71829', 'Flexibility and Efficiency', 'Provide accelerators for expert users while keeping the system accessible to novices.'),
('11db8175-ec5f-4c76-b026-b2ad73e71829', 'Aesthetic and Minimalist Design', 'Interfaces should not contain irrelevant information. Every extra unit of information competes for attention.'),
('11db8175-ec5f-4c76-b026-b2ad73e71829', 'Progressive Disclosure', 'Present only the essential information and actions users need at each step, revealing details progressively.'),
('11db8175-ec5f-4c76-b026-b2ad73e71829', 'Hierarchy', 'Organizing content and elements by importance using visual cues like size, color, contrast, and spacing.'),
('11db8175-ec5f-4c76-b026-b2ad73e71829', 'White Space', 'Empty space around elements that helps create visual hierarchy, improves readability, and reduces cognitive load.'),
('11db8175-ec5f-4c76-b026-b2ad73e71829', 'Mental Model', 'A person''s internal representation of how something works. Good design matches users'' mental models.');